    color: var(--text-heading);
}

/* ── Paragraph preview ── */
.cp-preview {
    display: flex;
    gap: 12px;
    padding: 14px 1.15rem;
    background: var(--bg-selection);
    flex-shrink: 0;
    border-bottom: 1px solid var(--border-card);
}

.cp-preview-bar {
    width: 3px;
    min-height: 100%;
    border-radius: 2px;
    background: var(--accent-amber);
    flex-shrink: 0;
}

.cp-preview-text {
    font-family: var(--font-serif);
    font-size: 0.82rem;
    font-style: italic;
    line-height: 1.6;
    color: var(--text-secondary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

/* ── Comment list ── */
.cp-list {
    flex: 1;
    overflow-y: auto;
    overflow-x: hidden;
    padding: 0.5rem 0;
}

.cp-list::-webkit-scrollbar {
    width: 5px;
}

.cp-list::-webkit-scrollbar-thumb {
    background: var(--accent-amber);
    border-radius: 4px;
}

.cp-list::-webkit-scrollbar-track {
    background: var(--bg-pill);
}

.cp-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 40px 0;
}

/* ── Empty state ── */
.cp-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 48px 24px;
    text-align: center;
}

.cp-empty-icon {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    background: var(--bg-selection);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 14px;
}

.cp-empty-icon svg {
    color: var(--accent-amber);
    opacity: 0.7;
}

.cp-empty-title {
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 600;
    color: var(--text-heading);
    margin: 0 0 4px;
}

.cp-empty-hint {
    font-family: var(--font-serif);
    font-size: 0.8rem;
    font-style: italic;
    color: var(--text-muted);
}

/* ── Input area ── */
.cp-input-area {
    display: flex;
    flex-direction: column;
    padding: 0.75rem 1.15rem;
    border-top: 1px solid var(--border-card);
    gap: 0.45rem;
    flex-shrink: 0;
}

.cp-reply-indicator {
    display: inline-flex;
    align-items: center;
    gap: 5px;
    padding: 3px 10px;
    background: var(--bg-selection);
    border-radius: 20px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--accent-amber);
    align-self: flex-start;
}

.cp-reply-indicator button {
    display: flex;
    align-items: center;
    justify-content: center;
    border: none;
    background: none;
    color: var(--text-muted);
    cursor: pointer;
    padding: 0;
    margin-left: 2px;
    font-size: 0.88rem;
    line-height: 1;
    transition: color 0.15s ease;
}

.cp-reply-indicator button:hover {
    color: var(--text-heading);
}

.cp-input-row {
    display: flex;
    align-items: flex-end;
    gap: 0.75rem;
}

.cp-textarea {
    flex: 1;
    font-family: var(--font-ui);
    font-size: 0.84rem;
    background-color: var(--bg-pill);
    color: var(--text-primary);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    padding: 0.55rem 0.75rem;
    resize: none;
    min-height: 1.4rem;
    max-height: 80px;
    outline: none;
    overflow-y: auto;
    transition: border-color 0.2s ease;
}

