}

.cp-submit {
    cursor: pointer;
    border: none;
    padding: 0.4rem 1.1rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    flex-shrink: 0;
    transition: opacity 0.15s ease;
}

.cp-submit:hover {
    opacity: 0.88;
}

.cp-submit:disabled {
    cursor: default;
    opacity: 0.4;
}

.cp-action-row {
    display: flex;
