// Delegated click + touchend handlers on the container
useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const handleTouchEnd = (e) => {
        const idx = getParagraphIndex(e.target);
        if (idx == null) return;

        touchHandledRef.current = true;
        clearLeaveTimer();
        clickedRef.current = true;
        setHoveredIndex(idx);
        setClickSeq(c => c + 1);
